 declare(strict_types=1); namespace FilesManager; class Auth { private $authCallback; private array $allowedIps; private bool $corsEnabled; private array $corsAllowedOrigins; private bool $rateLimitEnabled; private int $rateLimitMaxRequests; private int $rateLimitWindow; private string $rateLimitFile; public function __construct() { $this->authCallback = defined('AUTH_CALLBACK') && is_callable(AUTH_CALLBACK) ? AUTH_CALLBACK : null; $this->allowedIps = defined('ALLOWED_IPS') && is_array(ALLOWED_IPS) ? ALLOWED_IPS : []; $this->corsEnabled = defined('CORS_ENABLED') && CORS_ENABLED === true; $this->corsAllowedOrigins = defined('CORS_ALLOWED_ORIGINS') && is_array(CORS_ALLOWED_ORIGINS) ? CORS_ALLOWED_ORIGINS : ['*']; $this->rateLimitEnabled = defined('RATE_LIMIT_ENABLED') && RATE_LIMIT_ENABLED === true; $this->rateLimitMaxRequests = defined('RATE_LIMIT_MAX_REQUESTS') ? (int)RATE_LIMIT_MAX_REQUESTS : 100; $this->rateLimitWindow = defined('RATE_LIMIT_WINDOW') ? (int)RATE_LIMIT_WINDOW : 60; $this->rateLimitFile = defined('BASE_PATH') ? BASE_PATH . '/cache/rate-limit.json' : sys_get_temp_dir() . '/files-manager-rate-limit.json'; if ($this->corsEnabled) { $this->applyCorsHeaders(); } if ($this->rateLimitEnabled) { $this->checkRateLimit(); } } public function isAuthenticated(): bool { if ($this->authCallback === null) { return true; } try { $result = call_user_func($this->authCallback); return (bool)$result; } catch (\Exception $e) { error_log("Auth: Erro no AUTH_CALLBACK: " . $e->getMessage()); return false; } } public function isIpAllowed(): bool { if (empty($this->allowedIps)) { return true; } $clientIp = $this->getClientIp(); foreach ($this->allowedIps as $allowedIp) { if ($this->ipInRange($clientIp, $allowedIp)) { return true; } } return false; } private function applyCorsHeaders(): void { $origin = $_SERVER['HTTP_ORIGIN'] ?? ''; if (in_array('*', $this->corsAllowedOrigins, true)) { header('Access-Control-Allow-Origin: *'); } elseif (in_array($origin, $this->corsAllowedOri