) { $ip = $_SERVER[$header]; if (strpos($ip, ',') !== false) { $ip = explode(',', $ip)[0]; } $ip = trim($ip); if (filter_var($ip, FILTER_VALIDATE_IP)) { return $ip; } } } return '0.0.0.0'; } private function ipInRange(string $ip, string $range): bool { if (strpos($range, '/') === false) { return $ip === $range; } if (!filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV4)) { return false; } [$subnet, $mask] = explode('/', $range); $ipLong = ip2long($ip); $subnetLong = ip2long($subnet); $maskLong = -1 << (32 - (int)$mask); return ($ipLong & $maskLong) === ($subnetLong & $maskLong); } public function getSecurityInfo(): array { return [ 'auth_enabled' => $this->authCallback !== null, 'ip_whitelist_enabled' => !empty($this->allowedIps), 'cors_enabled' => $this->corsEnabled, 'rate_limit_enabled' => $this->rateLimitEnabled, 'rate_limit_max_requests' => $this->rateLimitMaxRequests, 'rate_limit_window' => $this->rateLimitWindow ]; } } 